import{_ as t,o as a,c as o,ag as r}from"./chunks/framework.DXGyWiRo.js";const u=JSON.parse('{"title":"EVIL-ESP","description":"Portable ESP8266 evil device — beacon spam, captive portal, evil twin.","frontmatter":{"title":"EVIL-ESP","description":"Portable ESP8266 evil device — beacon spam, captive portal, evil twin."},"headers":[],"relativePath":"microcontrollers-and-socs/esp32/evil-esp.md","filePath":"microcontrollers-and-socs/esp32/evil-esp.md"}'),n={name:"microcontrollers-and-socs/esp32/evil-esp.md"};function i(l,e,s,d,c,p){return a(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="evil-esp" tabindex="-1">EVIL-ESP <a class="header-anchor" href="#evil-esp" aria-label="Permalink to &quot;EVIL-ESP&quot;">​</a></h1><p>A super portable evil device based on the <strong>ESP8266</strong>, running <strong>MicroPython</strong>, with a single button and small OLED display.</p><h2 id="source" tabindex="-1">Source <a class="header-anchor" href="#source" aria-label="Permalink to &quot;Source&quot;">​</a></h2><ul><li><a href="https://github.com/tomellericcardo/EVIL-ESP" target="_blank" rel="noreferrer">tomellericcardo/EVIL-ESP</a></li></ul><h2 id="attacks" tabindex="-1">Attacks <a class="header-anchor" href="#attacks" aria-label="Permalink to &quot;Attacks&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Attack</th><th>Behavior</th></tr></thead><tbody><tr><td><strong>Beacon spammer</strong></td><td>Floods fake WiFi beacons so many phantom APs appear nearby</td></tr><tr><td><strong>Captive portal</strong></td><td>Hosts a “free hotspot” and redirects users to a registration page (credentials logged, no real sign-in)</td></tr><tr><td><strong>Evil twin</strong></td><td>Clones a protected network’s ESSID as an open AP; captive portal asks for the WiFi password “to complete a firmware upgrade”</td></tr></tbody></table><p>Credentials land in <code>data/captive_portal/log.csv</code> and <code>data/evil_twin/log.csv</code> (viewable on-device or on the MicroPython console at startup).</p><h2 id="installation" tabindex="-1">Installation <a class="header-anchor" href="#installation" aria-label="Permalink to &quot;Installation&quot;">​</a></h2><ol><li>Wire an I2C OLED and push button (pin with pull-up)</li><li>Flash MicroPython from the repo <code>firmware/</code> folder</li><li>Edit <code>data/config/config.json</code> for hardware and preferences</li><li>Upload the project tree (<code>ampy</code> or similar)</li></ol><p>Optional external antenna and power bank for portability. <strong>Headless mode:</strong> disable display/button in config and set the startup attack (evil twin needs target SSID in config).</p><h2 id="configuration-mode" tabindex="-1">Configuration mode <a class="header-anchor" href="#configuration-mode" aria-label="Permalink to &quot;Configuration mode&quot;">​</a></h2><p>Start config mode, join the board’s setup AP, and change attack options in the captive config page without reflashing.</p><h2 id="deauthentication-note" tabindex="-1">Deauthentication note <a class="header-anchor" href="#deauthentication-note" aria-label="Permalink to &quot;Deauthentication note&quot;">​</a></h2><p>MicroPython cannot send 802.11 deauth frames on current Espressif SDK versions. For evil-twin workflows, the repo includes a separate <a href="https://github.com/tomellericcardo/EVIL-ESP/tree/master/deauther" target="_blank" rel="noreferrer">Arduino deauther sketch</a> for another ESP8266, or use authorized lab tooling on Linux.</p><blockquote><p>Use responsibly and only on networks you own or are permitted to test.</p></blockquote><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="./esp32-wifi-penetration-tool.html">ESP32 WiFi Penetration Tool</a></li><li><a href="./esptool.html">esptool</a></li></ul>',17)])])}const m=t(n,[["render",i]]);export{u as __pageData,m as default};
